"""Port for durable audit-event persistence."""

from __future__ import annotations

from typing import Protocol

from scc_cli.core.contracts import AuditEvent


class AuditEventSink(Protocol):
    """Persist canonical audit events to a durable sink."""

    def append(self, event: AuditEvent) -> None:
        """Append one audit event to the sink."""

    def describe_destination(self) -> str:
        """Return a human-readable destination description for error messages."""

class LaunchPreflightError(ConfigError):
    """Launch was blocked before runtime startup."""

    provider_id: str = ""
    network_policy: str = ""
    required_destination_sets: tuple[str, ...] = field(default_factory=tuple)


@dataclass
class InvalidLaunchPlanError(LaunchPreflightError):
    """Prepared launch metadata is missing or malformed."""

    reason: str = "Launch plan is invalid."
    user_message: str = field(default="")
    suggested_action: str = field(
        default="Repair the provider launch wiring and try the command again."
    )

    def __post_init__(self) -> None:
        if not self.user_message:
            self.user_message = self.reason


@dataclass
class LaunchPolicyBlockedError(LaunchPreflightError):
    """Launch cannot proceed under the current network policy."""

    user_message: str = field(default="")
    suggested_action: str = field(
        default=(
            "Choose a less restrictive network policy or use a provider whose "
            "required destination sets are allowed."
        )
    )

    def __post_init__(self) -> None:
        if not self.user_message:
            required = ", ".join(self.required_destination_sets) or "none"
            provider = self.provider_id or "unknown"
            policy = self.network_policy or "unknown"
            self.user_message = (
                f"Launch blocked before startup: provider '{provider}' requires "
                f"destination sets [{required}] but the current network policy is '{policy}'."
            )


@dataclass
class LaunchAuditWriteError(ConfigError):
    """Launch audit event could not be persisted."""

    audit_destination: str = ""
    event_type: str = ""
    reason: str = ""
    user_message: str = field(default="")
    suggested_action: str = field(
        default="Check that SCC's local audit path exists and is writable, then retry."
    )

    def __post_init__(self) -> None:
        if not self.user_message:
            destination = self.audit_destination or "the configured audit sink"
            self.user_message = f"Failed to write launch audit event to {destination}."
        if not self.debug_context:
            details = []
            if self.event_type:
                details.append(f"event_type={self.event_type}")
            if self.reason:
                details.append(f"error={self.reason}")
            if details:
                self.debug_context = "\n".join(details)


@dataclass
class LaunchAuditUnavailableError(ConfigError):
    """Launch auditing is required but the sink is not wired."""

    user_message: str = field(default="Launch audit sink is not configured.")
    suggested_action: str = field(
        default="Use the SCC-wired launch dependency builder so preflight can audit before startup."
    )

    if effective_config:
        from scc_cli.bootstrap import merge_mcp_servers

        settings = merge_mcp_servers(settings, effective_config)

    if not settings:
        return None

    settings_path = Path("/home/agent") / AGENT_CONFIG_DIR / "settings.json"
    return agent_runner.build_settings(settings, path=settings_path)


def _resolve_current_branch(workspace_path: Path, git_client: GitClient) -> str | None:
    try:
        if not git_client.is_git_repo(workspace_path):
            return None
        return git_client.get_current_branch(workspace_path)
    except (OSError, ValueError):
        return None


def _build_sandbox_spec(
    *,
    request: StartSessionRequest,
    resolver_result: ResolverResult,
    effective_config: EffectiveConfig | None,
    agent_settings: AgentSettings | None,
) -> SandboxSpec | None:
    if request.dry_run:
        return None
    return SandboxSpec(
        image=SANDBOX_IMAGE,
        workspace_mount=MountSpec(
            source=resolver_result.mount_root,
            target=resolver_result.mount_root,
        ),
        workdir=Path(resolver_result.container_workdir),
        network_policy=effective_config.network_policy if effective_config else None,
        continue_session=request.resume,
        force_new=request.fresh,
        agent_settings=agent_settings,
        org_config=request.org_config,
    )


def _build_agent_launch_spec(
    *,
    request: StartSessionRequest,
    agent_settings: AgentSettings | None,
    dependencies: StartSessionDependencies,
) -> AgentLaunchSpec | None:
    """Delegate launch spec construction to the provider adapter.

    Returns None when no provider is wired (backward compat) or in dry-run mode.
    The provider resolves its own argv, env, and artifact paths from the settings
    artifact already built by the sync/build_agent_settings path.
    """
    if request.dry_run:
        return None
    provider = dependencies.agent_provider
    if provider is None:
        return None
    settings_path = agent_settings.path if agent_settings is not None else None
    config: dict[str, Any] = {}
    if agent_settings is not None:
        config = dict(agent_settings.content)
    return provider.prepare_launch(
        config=config,
        workspace=request.workspace_path,
        settings_path=settings_path,
    )
